// ═══════════════════════════════════════════════════
// Parse Notion webhook / internal trigger
// Normalize into NOIZY project event format
// ═══════════════════════════════════════════════════
const body = $input.first().json.body || $input.first().json;

const event = {
  source: 'notion',
  page_id: body.page_id || body.id || '',
  database_id: body.database_id || '',
  action: body.action || 'update',
  properties: body.properties || {},
  title: '',
  status: '',
  priority: '',
  assignee: '',
  labels: [],
  url: body.url || `https://notion.so/${(body.page_id || '').replace(/-/g, '')}`,
  timestamp: new Date().toISOString()
};

// Extract common properties
if (event.properties.Name?.title) {
  event.title = event.properties.Name.title.map(t => t.plain_text).join('');
} else if (event.properties.Task?.title) {
  event.title = event.properties.Task.title.map(t => t.plain_text).join('');
}
if (event.properties.Status?.select) {
  event.status = event.properties.Status.select.name;
}
if (event.properties.Priority?.select) {
  event.priority = event.properties.Priority.select.name;
}
if (event.properties.Assignee?.people) {
  event.assignee = event.properties.Assignee.people.map(p => p.name).join(', ');
}

return [{ json: event }];

// Status = Deploy → trigger GitHub deployment
const event = $input.first().json;

return [{
  json: {
    ...event,
    deploy_request: {
      repo: event.properties?.Repository?.select?.name || 'noizy-main',
      branch: 'main',
      environment: event.properties?.Environment?.select?.name || 'production',
      triggered_by: `notion-dashboard/${event.page_id}`,
      timestamp: new Date().toISOString()
    }
  }
}];

// Non-deploy updates → sync to Linear + GABRIEL
const event = $input.first().json;

// Map Notion status to Linear state
const statusToLinear = {
  'To Do': 'Todo',
  'In Progress': 'In Progress',
  'In Review': 'In Review',
  'Done': 'Done',
  'Backlog': 'Backlog',
  'Blocked': 'In Progress',
  'Archived': 'Canceled'
};

const linearState = statusToLinear[event.status] || null;

return [{
  json: {
    ...event,
    linear_sync: linearState ? {
      title: event.title,
      state: linearState,
      priority: event.priority === 'Urgent' ? 1 : event.priority === 'High' ? 2 : 3
    } : null,
    gabriel_event: {
      type: 'notion_update',
      summary: `Notion: "${event.title}" → ${event.status}`,
      severity: event.priority === 'Urgent' ? 'high' : 'low',
      source: 'notion',
      page_id: event.page_id,
      timestamp: new Date().toISOString()
    }
  }
}];

