// ═══════════════════════════════════════════════════
// Process Notion poll results into project status summary
// Feed to GABRIEL as a dashboard update
// ═══════════════════════════════════════════════════
const response = $input.first().json;
const pages = response.results || [];

if (pages.length === 0) {
  return [{ json: { _skip: true, message: 'No recent project updates' } }];
}

const projects = pages.map(page => {
  const props = page.properties || {};
  return {
    id: page.id,
    title: (props.Name?.title || props.Task?.title || []).map(t => t.plain_text).join('') || 'Untitled',
    status: props.Status?.select?.name || 'Unknown',
    priority: props.Priority?.select?.name || 'Medium',
    assignee: (props.Assignee?.people || []).map(p => p.name).join(', '),
    last_edited: page.last_edited_time,
    url: page.url
  };
});

// Build summary
const byStatus = {};
projects.forEach(p => {
  byStatus[p.status] = (byStatus[p.status] || 0) + 1;
});

return [{
  json: {
    source: 'notion-poll',
    project_count: projects.length,
    status_summary: byStatus,
    projects: projects,
    polled_at: new Date().toISOString()
  }
}];
